from flask import Flask, jsonify
from pymemcache.client import base
import pymysql
import hashlib

app = Flask(__name__)

# Configure Memcached
memcached_client = base.Client(('localhost', 11211))

# Configure MySQL Database
db_config = {
    'host': 'localhost',
    'user': 'your_user',
    'password': 'your_password',
    'database': 'your_database'
}

def get_db_connection():
    return pymysql.connect(**db_config)

def cache_key(query, params):
    key = f"{query}:{params}"
    return hashlib.sha256(key.encode()).hexdigest()

def get_cached_data(key):
    return memcached_client.get(key)

def set_cache_data(key, value, ttl):
    memcached_client.set(key, value, expire=ttl)

@app.route('/data')
def get_data():
    query = "SELECT * FROM your_table"
    params = ()
    key = cache_key(query, params)
    
    cached_result = get_cached_data(key)
    if cached_result:
        return jsonify(cached_result)
    
    connection = get_db_connection()
    try:
        with connection.cursor() as cursor:
            cursor.execute(query, params)
            result = cursor.fetchall()
            set_cache_data(key, result, ttl=300)  # Cache for 5 minutes
            return jsonify(result)
    finally:
        connection.close()

@app.route('/api/resource')
def api_resource():
    key = 'api_resource'
    cached_response = get_cached_data(key)
    if cached_response:
        return jsonify(cached_response)
    
    response_data = {'message': 'This is a resource from the API'}
